sealed class DataException: kotlin.Exception() {
    
    /**
     * Invalid key provided (key is empty)
     */
    class InvalidKey(
        ) : DataException() {
        override val message
            get() = ""
    }
    
    /**
     * Key not found in store
     */
    class KeyNotFound(
        
        /**
         * The key that was not found
         */
        val `key`: kotlin.String
        ) : DataException() {
        override val message
            get() = "key=${ `key` }"
    }
    
    /**
     * Storage limit exceeded
     */
    class StorageLimitExceeded(
        
        /**
         * Maximum allowed entries
         */
        val `max`: kotlin.ULong
        ) : DataException() {
        override val message
            get() = "max=${ `max` }"
    }
    
    /**
     * TTL exceeds maximum allowed
     */
    class TtlExceeded(
        
        /**
         * The requested TTL in seconds
         */
        val `requested`: kotlin.ULong, 
        
        /**
         * The maximum allowed TTL in seconds
         */
        val `max`: kotlin.ULong
        ) : DataException() {
        override val message
            get() = "requested=${ `requested` }, max=${ `max` }"
    }
    
    /**
     * Value too large
     */
    class ValueTooLarge(
        
        /**
         * Actual size in bytes
         */
        val `size`: kotlin.ULong, 
        
        /**
         * Maximum allowed size in bytes
         */
        val `max`: kotlin.ULong
        ) : DataException() {
        override val message
            get() = "size=${ `size` }, max=${ `max` }"
    }
    
    /**
     * Serialization error
     */
    class SerializationException(
        
        val v1: kotlin.String
        ) : DataException() {
        override val message
            get() = "v1=${ v1 }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<DataException> {
        override fun lift(error_buf: RustBuffer.ByValue): DataException = FfiConverterTypeDataError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeDataError : FfiConverterRustBuffer<DataException> {
    override fun read(buf: ByteBuffer): DataException {
        

        return when(buf.getInt()) {
            1 -> DataException.InvalidKey()
            2 -> DataException.KeyNotFound(
                FfiConverterString.read(buf),
                )
            3 -> DataException.StorageLimitExceeded(
                FfiConverterULong.read(buf),
                )
            4 -> DataException.TtlExceeded(
                FfiConverterULong.read(buf),
                FfiConverterULong.read(buf),
                )
            5 -> DataException.ValueTooLarge(
                FfiConverterULong.read(buf),
                FfiConverterULong.read(buf),
                )
            6 -> DataException.SerializationException(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: DataException): ULong {
        return when(value) {
            is DataException.InvalidKey -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is DataException.KeyNotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`key`)
            )
            is DataException.StorageLimitExceeded -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterULong.allocationSize(value.`max`)
            )
            is DataException.TtlExceeded -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterULong.allocationSize(value.`requested`)
                + FfiConverterULong.allocationSize(value.`max`)
            )
            is DataException.ValueTooLarge -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterULong.allocationSize(value.`size`)
                + FfiConverterULong.allocationSize(value.`max`)
            )
            is DataException.SerializationException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
        }
    }

    override fun write(value: DataException, buf: ByteBuffer) {
        when(value) {
            is DataException.InvalidKey -> {
                buf.putInt(1)
                Unit
            }
            is DataException.KeyNotFound -> {
                buf.putInt(2)
                FfiConverterString.write(value.`key`, buf)
                Unit
            }
            is DataException.StorageLimitExceeded -> {
                buf.putInt(3)
                FfiConverterULong.write(value.`max`, buf)
                Unit
            }
            is DataException.TtlExceeded -> {
                buf.putInt(4)
                FfiConverterULong.write(value.`requested`, buf)
                FfiConverterULong.write(value.`max`, buf)
                Unit
            }
            is DataException.ValueTooLarge -> {
                buf.putInt(5)
                FfiConverterULong.write(value.`size`, buf)
                FfiConverterULong.write(value.`max`, buf)
                Unit
            }
            is DataException.SerializationException -> {
                buf.putInt(6)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




